ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?filmmaker WHERE {
  ?movies a :Movie .
  ?moviegenre a :MovieGenre .
  ?moviegenre p:hasMovies ?movies .
  ?genres a :Genre .
  ?moviegenre p:hasGenres ?genres .
  ?movies p:Filmmaker ?filmmaker .
  ?genres p:Type ?type_f .
  FILTER(STR(?type_f) = "Drama")
} }
  full: { SELECT ?filmmaker ?screenwriter WHERE {
  ?movies a :Movie .
  ?moviegenre a :MovieGenre .
  ?moviegenre p:hasMovies ?movies .
  ?genres a :Genre .
  ?moviegenre p:hasGenres ?genres .
  ?movies p:Filmmaker ?filmmaker .
  ?movies p:Screenwriter ?screenwriter .
  ?genres p:Type ?type_f .
  FILTER(STR(?type_f) = "Drama")
} }
  component_2: { SELECT ?screenwriter WHERE {
  ?movies a :Movie .
  ?moviegenre a :MovieGenre .
  ?moviegenre p:hasMovies ?movies .
  ?genres a :Genre .
  ?moviegenre p:hasGenres ?genres .
  ?movies p:Screenwriter ?screenwriter .
  ?genres p:Type ?type_f .
  FILTER(STR(?type_f) = "Drama")
} }
}
